import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

type WeatherCondition = 'sunny' | 'cloudy' | 'partly-cloudy' | 'rainy' | 'stormy' | 'snowy';

interface ForecastDay {
  day: string;
  condition: WeatherCondition;
  high: number;
  low: number;
}

interface WeatherProps {
  location?: string;
  currentTemp?: number;
  condition?: WeatherCondition;
  conditionText?: string;
  humidity?: number;
  windSpeed?: number;
  forecast?: ForecastDay[];
  unit?: 'C' | 'F';
}

interface Props {
  properties: WeatherProps;
}

function useComponent(props: Props) {
  const {
    location = 'San Francisco, CA',
    currentTemp = 68,
    condition = 'partly-cloudy',
    conditionText = 'Partly Cloudy',
    humidity = 45,
    windSpeed = 12,
    forecast = [
      { day: 'Mon', condition: 'sunny', high: 72, low: 55 },
      { day: 'Tue', condition: 'partly-cloudy', high: 70, low: 54 },
      { day: 'Wed', condition: 'cloudy', high: 68, low: 53 },
      { day: 'Thu', condition: 'rainy', high: 62, low: 50 },
      { day: 'Fri', condition: 'sunny', high: 75, low: 56 },
    ],
    unit = 'F'
  } = props.properties || {};

  return {
    location,
    currentTemp,
    condition,
    conditionText,
    humidity,
    windSpeed,
    forecast,
    unit
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const conditionToEmoji: Record<string, string> = {
    sunny: '☀️',
    cloudy: '☁️',
    'partly-cloudy': '⛅',
    rainy: '🌧️',
    stormy: '⛈️',
    snowy: '❄️',
  };

  return (
    <Card shadow="md" padding={32} radius="xl">
      <Stack gap={32}>
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={2}>{state.location}</Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {state.conditionText}
            </Text>
          </Stack>
          <div style={{ fontSize: '56px', lineHeight: 1 }}>
            {conditionToEmoji[state.condition] || '☁️'}
          </div>
        </Stack>

        <Stack direction="horizontal" justify="between" align="end">
          <div style={{ fontSize: '80px', fontWeight: 'var(--ggui-font-weight-bold, 700)', lineHeight: '1', letterSpacing: '-0.02em', color: 'var(--ggui-color-onSurface, #18181b)' }}>
            {state.currentTemp}°<span style={{ fontSize: '40px', color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}>{state.unit}</span>
          </div>

          <Stack direction="horizontal" gap={0} align="center">
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="bodyLarge" weight="semibold">{state.humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={24} />
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text variant="bodyLarge" weight="semibold">{state.windSpeed} {state.unit === 'F' ? 'mph' : 'km/h'}</Text>
            </Stack>
          </Stack>
        </Stack>

        <Divider margin={0} />

        <Stack direction="horizontal" justify="between" align="center">
          {state.forecast.map((day, i) => (
            <Stack key={i} gap={8} align="center">
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {day.day}
              </Text>
              <div style={{ fontSize: '32px', lineHeight: 1 }}>
                {conditionToEmoji[day.condition] || '☁️'}
              </div>
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="bodySmall" weight="semibold">{day.high}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{day.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export interface ElementData {
  name: string;
  symbol: string;
  atomicNumber: number;
  atomicWeight: number | string;
  category: string;
  xpos: number;
  ypos: number;
}

interface Props {
  elements?: ElementData[];
}

const DEFAULT_ELEMENTS: ElementData[] = [
  { name: 'Hydrogen', symbol: 'H', atomicNumber: 1, atomicWeight: 1.008, category: 'diatomic nonmetal', xpos: 1, ypos: 1 },
  { name: 'Helium', symbol: 'He', atomicNumber: 2, atomicWeight: 4.0026, category: 'noble gas', xpos: 18, ypos: 1 },
  { name: 'Lithium', symbol: 'Li', atomicNumber: 3, atomicWeight: 6.94, category: 'alkali metal', xpos: 1, ypos: 2 },
  { name: 'Beryllium', symbol: 'Be', atomicNumber: 4, atomicWeight: 9.0122, category: 'alkaline earth metal', xpos: 2, ypos: 2 },
  { name: 'Boron', symbol: 'B', atomicNumber: 5, atomicWeight: 10.81, category: 'metalloid', xpos: 13, ypos: 2 },
  { name: 'Carbon', symbol: 'C', atomicNumber: 6, atomicWeight: 12.011, category: 'polyatomic nonmetal', xpos: 14, ypos: 2 },
  { name: 'Nitrogen', symbol: 'N', atomicNumber: 7, atomicWeight: 14.007, category: 'diatomic nonmetal', xpos: 15, ypos: 2 },
  { name: 'Oxygen', symbol: 'O', atomicNumber: 8, atomicWeight: 15.999, category: 'diatomic nonmetal', xpos: 16, ypos: 2 },
  { name: 'Fluorine', symbol: 'F', atomicNumber: 9, atomicWeight: 18.998, category: 'halogen', xpos: 17, ypos: 2 },
  { name: 'Neon', symbol: 'Ne', atomicNumber: 10, atomicWeight: 20.180, category: 'noble gas', xpos: 18, ypos: 2 },
  { name: 'Sodium', symbol: 'Na', atomicNumber: 11, atomicWeight: 22.990, category: 'alkali metal', xpos: 1, ypos: 3 },
  { name: 'Magnesium', symbol: 'Mg', atomicNumber: 12, atomicWeight: 24.305, category: 'alkaline earth metal', xpos: 2, ypos: 3 },
  { name: 'Aluminum', symbol: 'Al', atomicNumber: 13, atomicWeight: 26.982, category: 'post-transition metal', xpos: 13, ypos: 3 },
  { name: 'Silicon', symbol: 'Si', atomicNumber: 14, atomicWeight: 28.085, category: 'metalloid', xpos: 14, ypos: 3 },
  { name: 'Phosphorus', symbol: 'P', atomicNumber: 15, atomicWeight: 30.974, category: 'polyatomic nonmetal', xpos: 15, ypos: 3 },
  { name: 'Sulfur', symbol: 'S', atomicNumber: 16, atomicWeight: 32.06, category: 'polyatomic nonmetal', xpos: 16, ypos: 3 },
  { name: 'Chlorine', symbol: 'Cl', atomicNumber: 17, atomicWeight: 35.45, category: 'halogen', xpos: 17, ypos: 3 },
  { name: 'Argon', symbol: 'Ar', atomicNumber: 18, atomicWeight: 39.95, category: 'noble gas', xpos: 18, ypos: 3 },
  { name: 'Potassium', symbol: 'K', atomicNumber: 19, atomicWeight: 39.098, category: 'alkali metal', xpos: 1, ypos: 4 },
  { name: 'Calcium', symbol: 'Ca', atomicNumber: 20, atomicWeight: 40.078, category: 'alkaline earth metal', xpos: 2, ypos: 4 },
];

const CATEGORY_COLORS: Record<string, string> = {
  'diatomic nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
  'noble gas': 'var(--ggui-color-info-100, #cffafe)',
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'metalloid': 'var(--ggui-color-warning-200, #fde68a)',
  'polyatomic nonmetal': 'var(--ggui-color-success-200, #bbf7d0)',
  'transition metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'lanthanide': 'var(--ggui-color-success-300, #86efac)',
  'actinide': 'var(--ggui-color-error-200, #fecaca)',
  'halogen': 'var(--ggui-color-info-200, #a5f3fc)'
};

const CATEGORY_BADGE_VARIANTS: Record<string, "default" | "primary" | "secondary" | "success" | "warning" | "error" | "info"> = {
  'diatomic nonmetal': 'success',
  'noble gas': 'info',
  'alkali metal': 'error',
  'alkaline earth metal': 'warning',
  'metalloid': 'warning',
  'polyatomic nonmetal': 'success',
  'transition metal': 'primary',
  'post-transition metal': 'primary',
  'lanthanide': 'success',
  'actinide': 'error',
  'halogen': 'info'
};

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const elements = useMemo(() => {
    return props.elements && props.elements.length > 0 ? props.elements : DEFAULT_ELEMENTS;
  }, [props.elements]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach(el => cats.add(el.category));
    return Array.from(cats).sort();
  }, [elements]);

  return {
    elements,
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    categories
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Box padding={24} background="var(--ggui-color-surface, #ffffff)">
      <Stack gap={24}>
        <Heading level={2}>Periodic Table of Elements</Heading>

        <SearchField 
          value={state.searchQuery}
          onChange={state.setSearchQuery}
          placeholder="Search elements by name or symbol..."
        />

        <div style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-2, 8px)' }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            minWidth: '900px'
          }}>
            {state.elements.map(el => {
              const query = state.searchQuery.toLowerCase();
              const isMatch = !query || el.name.toLowerCase().includes(query) || el.symbol.toLowerCase().includes(query);
              const bgColor = CATEGORY_COLORS[el.category.toLowerCase()] || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
              const isSelected = state.selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <div
                  key={el.atomicNumber}
                  onClick={() => state.setSelectedElement(el)}
                  style={{
                    gridColumn: el.xpos,
                    gridRow: el.ypos,
                    backgroundColor: bgColor,
                    opacity: isMatch ? 1 : 0.2,
                    border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    aspectRatio: '1',
                    transition: 'all 0.2s ease-in-out',
                    transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none'
                  }}
                >
                  <Text size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {el.atomicNumber}
                  </Text>
                  <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <Heading level={4} align="center">{el.symbol}</Heading>
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        {state.selectedElement ? (
          <Card padding={24} shadow="md" border>
            <Stack gap={16}>
              <Stack direction="horizontal" align="center" justify="between">
                <Heading level={3}>
                  {state.selectedElement.name} ({state.selectedElement.symbol})
                </Heading>
                <Badge size="lg" variant={CATEGORY_BADGE_VARIANTS[state.selectedElement.category.toLowerCase()] || 'default'}>
                  <div style={{ textTransform: 'capitalize' }}>
                    {state.selectedElement.category}
                  </div>
                </Badge>
              </Stack>
              <Divider margin={0} />
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 'var(--ggui-spacing-4, 16px)' }}>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                  <Text size="xl" weight="medium">{String(state.selectedElement.atomicNumber)}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                  <Text size="xl" weight="medium">{String(state.selectedElement.atomicWeight)}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                  <div style={{ textTransform: 'capitalize' }}>
                    <Text size="xl" weight="medium">{state.selectedElement.category}</Text>
                  </div>
                </Box>
              </div>
            </Stack>
          </Card>
        ) : (
          <div style={{
            padding: 'var(--ggui-spacing-6, 24px)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
          }}>
            <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select an element to view details</Text>
          </div>
        )}

        <Stack gap={12}>
          <Text variant="label">Legend</Text>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-4, 16px)' }}>
            {state.categories.map(cat => (
              <div key={cat} style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                <div style={{ 
                  width: '16px', 
                  height: '16px', 
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  backgroundColor: CATEGORY_COLORS[cat.toLowerCase()] || 'var(--ggui-color-surfaceVariant, #f4f4f5)' 
                }} />
                <div style={{ textTransform: 'capitalize' }}>
                  <Text size="sm">{cat}</Text>
                </div>
              </div>
            ))}
          </div>
        </Stack>

      </Stack>
    </Box>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: Props) {
  const properties = (props.properties as any) || {};
  const [step, setStep] = useState(1);
  const [name, setName] = useState(properties.name || '');
  const [email, setEmail] = useState(properties.email || '');
  const [avatar, setAvatar] = useState(properties.avatar || '🧑‍💻');
  const [role, setRole] = useState(properties.role || 'Developer');
  const [emailNotifications, setEmailNotifications] = useState(properties.emailNotifications ?? true);
  const [theme, setTheme] = useState(properties.theme || 'light');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isValidEmail = emailRegex.test(email);
  const emailError = (email.length > 0 && !isValidEmail) ? 'Invalid email format' : undefined;

  const canGoNext = useMemo(() => {
    if (step === 1) return name.trim() !== '' && isValidEmail;
    if (step === 2) return role !== '';
    return true;
  }, [step, name, isValidEmail, role]);

  const handleNext = useCallback(() => {
    if (step < 3) setStep(s => s + 1);
  }, [step]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep(s => s - 1);
  }, [step]);

  const handleComplete = useCallback(() => {
    const data = { name, email, avatar, role, emailNotifications, theme };
    if ((props as any).actions?.complete) {
      (props as any).actions.complete(data);
    }
  }, [props, name, email, avatar, role, emailNotifications, theme]);

  const progressValue = (step / 3) * 100;

  return {
    step, name, setName, email, setEmail, avatar, setAvatar, role, setRole,
    emailNotifications, setEmailNotifications, theme, setTheme, emailError,
    canGoNext, handleNext, handleBack, handleComplete, progressValue,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" padding={24}>
        <Card padding={32} shadow="md" radius="xl">
          <Stack gap={24}>
            {/* Header / Progress */}
            <Stack gap={8}>
              <Stack direction="horizontal" justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
                  Step {state.step} of 3
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {state.step === 1 ? 'Profile Setup' : state.step === 2 ? 'Preferences' : 'Review & Confirm'}
                </Text>
              </Stack>
              <Progress value={state.progressValue} max={100} variant="default" size="sm" />
            </Stack>

            <Divider margin={0} />

            {/* Step Content */}
            <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }} key={state.step}>
              {state.step === 1 && (
                <Stack gap={24}>
                  <Stack gap={4}>
                    <Heading level={3}>Profile Setup</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Let's start with your basic information.
                    </Text>
                  </Stack>

                  <Input label="Name" required value={state.name} onChange={state.setName} placeholder="Jane Doe" />

                  <Input label="Email" type="email" required value={state.email} onChange={state.setEmail} error={state.emailError} placeholder="jane@example.com" />

                  <Stack gap={8}>
                    <Text variant="label">Avatar</Text>
                    <Stack direction="horizontal" gap={12}>
                      {['🧑‍💻', '👩‍🎨', '👨‍💼', '🤖'].map(a => (
                        <Button 
                          key={a}
                          variant={state.avatar === a ? 'primary' : 'outline'}
                          onClick={() => state.setAvatar(a)}
                          size="lg"
                        >
                          <span style={{ fontSize: '24px' }}>{a}</span>
                        </Button>
                      ))}
                    </Stack>
                  </Stack>
                </Stack>
              )}

              {state.step === 2 && (
                <Stack gap={24}>
                  <Stack gap={4}>
                    <Heading level={3}>Preferences</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Customize your experience and notifications.
                    </Text>
                  </Stack>

                  <Select 
                    label="Role" 
                    value={state.role} 
                    onChange={state.setRole} 
                    options={[
                      { value: 'Developer', label: 'Developer' },
                      { value: 'Designer', label: 'Designer' },
                      { value: 'Manager', label: 'Manager' },
                      { value: 'Other', label: 'Other' },
                    ]}
                  />

                  <Box paddingY={8}>
                    <Toggle 
                      label="Email Notifications" 
                      checked={state.emailNotifications} 
                      onChange={state.setEmailNotifications} 
                      size="md"
                    />
                  </Box>

                  <RadioGroup 
                    label="Theme Preference" 
                    value={state.theme} 
                    onChange={state.setTheme}
                    options={[
                      { value: 'light', label: 'Light', description: 'Clean and bright' },
                      { value: 'dark', label: 'Dark', description: 'Easy on the eyes' },
                    ]}
                  />
                </Stack>
              )}

              {state.step === 3 && (
                <Stack gap={24}>
                  <Stack gap={4}>
                    <Heading level={3}>Review & Confirm</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Please review your details before completing setup.
                    </Text>
                  </Stack>

                  <Card padding={24} shadow="sm" radius="md">
                    <Stack gap={24}>
                      <Stack direction="horizontal" align="center" gap={16}>
                        <Box background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="50%" padding="16px">
                          <div style={{ fontSize: '32px', lineHeight: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', width: '32px', height: '32px' }}>
                            {state.avatar}
                          </div>
                        </Box>
                        <Stack gap={4}>
                          <Text variant="bodyLarge" weight="semibold">{state.name}</Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.email}</Text>
                        </Stack>
                      </Stack>

                      <Divider margin={0} />

                      <Stack gap={16}>
                        <Stack direction="horizontal" justify="between">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                          <Text variant="bodySmall" weight="medium">{state.role}</Text>
                        </Stack>
                        <Stack direction="horizontal" justify="between">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
                          <Text variant="bodySmall" weight="medium">{state.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                        </Stack>
                        <Stack direction="horizontal" justify="between">
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                          <Text variant="bodySmall" weight="medium">{state.theme === 'light' ? 'Light' : 'Dark'}</Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>
                </Stack>
              )}
            </div>

            <Divider margin={0} />

            {/* Footer Navigation */}
            <Stack direction="horizontal" justify="between" align="center">
              <Button 
                variant="ghost" 
                onClick={state.handleBack} 
                disabled={state.step === 1}
                leftIcon={<Icon name="chevron-left" />}
              >
                Go Back
              </Button>

              {state.step < 3 ? (
                <Button 
                  variant="primary" 
                  onClick={state.handleNext} 
                  disabled={!state.canGoNext}
                  rightIcon={<Icon name="chevron-right" />}
                >
                  Next Step
                </Button>
              ) : (
                <Button 
                  variant="primary" 
                  onClick={state.handleComplete}
                  leftIcon={<Icon name="check" />}
                >
                  Complete Setup
                </Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Container>
    </>
  );
}

