import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  row: number;
  col: number;
}

interface Props {
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-info-200, #cffafe)',
  'halogen': 'var(--ggui-color-warning-200, #fde68a)',
  'alkali-metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'alkaline-earth-metal': 'var(--ggui-color-success-200, #bbf7d0)',
  'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'post-transition-metal': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  'metalloid': 'var(--ggui-color-outlineVariant, #e4e4e7)',
  'reactive-nonmetal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'lanthanide': 'var(--ggui-color-container, #ede9fe)',
  'actinide': 'var(--ggui-color-container, #ede9fe)',
};

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return props.elements.filter(e => 
      e.name.toLowerCase().includes(q) || e.symbol.toLowerCase().includes(q)
    );
  }, [props.elements, search]);

  return { search, setSearch, selected, setSelected, filtered };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Periodic Table</Heading>
        <Input label="Search Elements" value={state.search} onChange={state.setSearch} placeholder="Name or symbol..." />

        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 'var(--ggui-spacing-1)',
          marginTop: 'var(--ggui-spacing-4)' 
        }}>
          {state.filtered.map(e => (
            <Box key={e.atomicNumber} style={{ gridRow: e.row, gridColumn: e.col }}>
              <div onClick={() => state.setSelected(e)} style={{ cursor: 'pointer' }}>
                <Card 
                  padding={8} 
                  shadow="sm"
                  border={true}
                  radius="sm"
                  style={{
                    backgroundColor: CATEGORY_COLORS[e.category] || 'var(--ggui-color-surface)',
                    opacity: state.search && !state.filtered.includes(e) ? 0.3 : 1
                  }}
                >
                  <Text variant="caption">{e.atomicNumber}</Text>
                  <Heading level={4} align="center">{e.symbol}</Heading>
                </Card>
              </div>
            </Box>
          ))}
        </div>

        {state.selected && (
          <Card padding={24}>
            <Heading level={2}>{state.selected.name} ({state.selected.symbol})</Heading>
            <Stack gap={8} style={{ marginTop: 'var(--ggui-spacing-4)' }}>
              <Text>Atomic Number: {state.selected.atomicNumber}</Text>
              <Text>Atomic Weight: {state.selected.atomicWeight}</Text>
              <Text>Category: {state.selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius={8}>
          <Heading level={5}>Legend</Heading>
          <Stack direction="horizontal" wrap={true} gap={16} style={{ marginTop: 'var(--ggui-spacing-2)' }}>
            {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
              <Stack key={cat} direction="horizontal" align="center" gap={8}>
                <div style={{ width: 16, height: 16, backgroundColor: color, borderRadius: 2 }} />
                <Text variant="caption">{cat.replace('-', ' ')}</Text>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  onComplete: (data: any) => void;
  initialData?: any;
}

function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: props.initialData?.name || '',
    email: props.initialData?.email || '',
    avatar: props.initialData?.avatar || '🧑‍💻',
    role: props.initialData?.role || 'Developer',
    emailNotifications: props.initialData?.emailNotifications ?? true,
    theme: props.initialData?.theme || 'light',
  });

  const update = (key: string, value: any) => setData((d) => ({ ...d, [key]: value }));

  const isValid = useMemo(() => {
    if (step === 1) return data.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email);
    return true;
  }, [step, data]);

  const handleNext = () => step < 3 ? setStep(s => s + 1) : props.onComplete(data);
  const handleBack = () => setStep(s => Math.max(1, s - 1));

  return { step, data, update, isValid, handleNext, handleBack };
}

export default function Component(props: Props) {
  const { step, data, update, isValid, handleNext, handleBack } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding ({step}/3)</Heading>
        <Progress value={(step - 1) * 50} />

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <Input label="Name" value={data.name} onChange={(v) => update('name', v)} required />
              <Input label="Email" type="email" value={data.email} onChange={(v) => update('email', v)} required />
              <Text variant="label">Select Avatar</Text>
              <Row gap={8}>
                {['🧑‍💻', '🎨', '💼', '🚀'].map(emoji => (
                  <Button key={emoji} variant={data.avatar === emoji ? 'primary' : 'outline'} onClick={() => update('avatar', emoji)}>
                    {emoji}
                  </Button>
                ))}
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Select label="Role" value={data.role} onChange={(v) => update('role', v)} options={[{value:'Developer', label:'Developer'}, {value:'Designer', label:'Designer'}, {value:'Manager', label:'Manager'}, {value:'Other', label:'Other'}]} />
              <Toggle label="Email Notifications" checked={data.emailNotifications} onChange={(v) => update('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={data.theme === 'dark'} onChange={(v) => update('theme', v ? 'dark' : 'light')} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Text>Review your details:</Text>
              <Card>
                <Stack gap={8}>
                  <Text>Name: {data.name}</Text>
                  <Text>Email: {data.email}</Text>
                  <Text>Role: {data.role}</Text>
                  <Text>Theme: {data.theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
          <Button onClick={handleNext} disabled={!isValid}>
            {step === 3 ? 'Complete Setup' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}
